import { GoogleGenAI, Modality, Chat, GenerateContentResponse } from "@google/genai";
import { ImageAspectRatio, Resolution, VideoAspectRatio } from "../types";
import { IMAGE_EDIT_MODEL, IMAGE_MODEL, VIDEO_MODEL, CHAT_MODEL, MELDA_SYSTEM_INSTRUCTION } from "../constants";

const STORAGE_API_KEY = 'hputrax_custom_api_key';

export const getApiKey = (): string | undefined => {
  if (typeof window !== 'undefined') {
    const storedKey = localStorage.getItem(STORAGE_API_KEY);
    if (storedKey && storedKey.trim().length > 0) {
      return storedKey;
    }
  }
  return process.env.API_KEY;
};

// Safety settings - Adjusted to be more permissive for creative tasks
const SAFETY_SETTINGS = [
    { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_ONLY_HIGH' },
    { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_ONLY_HIGH' },
    { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_ONLY_HIGH' },
    { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_ONLY_HIGH' }
];

// Helper to stagger requests to avoid rate limits
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const generateImages = async (
  prompt: string,
  numberOfImages: number,
  aspectRatio: ImageAspectRatio
): Promise<string[]> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key tidak ditemukan. Silakan atur di menu Admin.");

  const ai = new GoogleGenAI({ apiKey });

  // Gemini 2.5 Flash Image creates 1 image per request via generateContent.
  // To support multiple images, we send parallel requests.
  const generateSingleImage = async (index: number) => {
      // Stagger requests slightly to avoid burst rate limits (429)
      await delay(index * 350); 

      // Add slight variation to prompt if multiple images to ensure diversity
      const finalPrompt = numberOfImages > 1 
        ? `${prompt} --variation ${index + 1}` 
        : prompt;

      try {
          const response = await ai.models.generateContent({
              model: IMAGE_MODEL, // 'gemini-2.5-flash-image'
              contents: finalPrompt,
              config: {
                  responseModalities: [Modality.IMAGE],
                  imageConfig: { aspectRatio: aspectRatio },
                  safetySettings: SAFETY_SETTINGS,
              },
          });

          // Robust checking for parts to avoid "undefined" errors
          const parts = response.candidates?.[0]?.content?.parts;
          if (parts && parts.length > 0) {
              const imagePart = parts.find((p: any) => p.inlineData);
              if (imagePart && imagePart.inlineData) {
                  return `data:${imagePart.inlineData.mimeType};base64,${imagePart.inlineData.data}`;
              }
          }
          return null;
      } catch (e) {
          console.warn(`Image generation attempt ${index+1} failed:`, e);
          return null;
      }
  };

  try {
      const promises = Array.from({ length: numberOfImages }, (_, i) => generateSingleImage(i));
      const results = await Promise.all(promises);

      // Filter out nulls (failed generations)
      const validImages = results.filter((img): img is string => img !== null);

      if (validImages.length === 0) {
          throw new Error("AI gagal membuat gambar. Silakan coba lagi atau ubah prompt Anda. (Mungkin konten diblokir oleh filter keamanan atau batas limit tercapai)");
      }

      return validImages;
  } catch (error) {
      console.error("Image generation failed", error);
      throw error;
  }
};

export const editImage = async (
  prompt: string,
  images: { data: string; mimeType: string }[],
  aspectRatio?: ImageAspectRatio,
  numberOfImages: number = 1
): Promise<string[]> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key tidak ditemukan. Silakan atur di menu Admin.");

  const ai = new GoogleGenAI({ apiKey });

  // Gemini 2.5 Flash Image returns 1 result per generateContent call.
  // To get multiple concepts, we fire parallel requests.
  const generateSingleConcept = async (index: number) => {
      // Stagger requests slightly to avoid burst rate limits (429)
      await delay(index * 350);

      const parts: any[] = [];

      // Add all images to the payload
      images.forEach(img => {
        parts.push({
          inlineData: {
            data: img.data,
            mimeType: img.mimeType,
          },
        });
      });

      // Add the text prompt, adding variation noise if multiple are requested
      // to ensure the model doesn't generate identical pixels
      const specificPrompt = numberOfImages > 1 
        ? `${prompt} (Creative Variation ${index + 1})` 
        : prompt;

      parts.push({
        text: specificPrompt,
      });

      try {
        const response = await ai.models.generateContent({
            model: IMAGE_EDIT_MODEL,
            contents: {
              parts: parts,
            },
            config: {
              responseModalities: [Modality.IMAGE], // Strictly request IMAGE
              imageConfig: aspectRatio ? { aspectRatio: aspectRatio } : undefined,
              safetySettings: SAFETY_SETTINGS,
            },
        });

        const results: string[] = [];
        let refusalText = "";

        const content = response.candidates?.[0]?.content;
        if (content && content.parts) {
            for (const part of content.parts) {
                if (part.inlineData) {
                    results.push(`data:${part.inlineData.mimeType};base64,${part.inlineData.data}`);
                } else if (part.text) {
                    refusalText += part.text;
                }
            }
        }

        // If no images were generated but we got text, it's likely a refusal/error from the model
        if (results.length === 0 && refusalText) {
            console.warn(`Model Refusal: ${refusalText}`);
            throw new Error(`AI Menolak: ${refusalText.slice(0, 100)}...`);
        }

        return results;
      } catch (e: any) {
        console.warn(`Edit attempt ${index+1} failed:`, e.message);
        // If it's a specific refusal error we threw above, rethrow it so the main catch block sees it
        if (e.message.startsWith('AI Menolak')) throw e;
        return [];
      }
  };

  try {
      const promises = Array.from({ length: numberOfImages }, (_, i) => generateSingleConcept(i));
      const results = await Promise.all(promises);
      const flattened = results.flat();

      if (flattened.length === 0) {
          throw new Error("AI tidak menghasilkan gambar. Kemungkinan prompt ditolak oleh filter keamanan atau tidak valid.");
      }
      return flattened;
  } catch (error: any) {
      console.error("Edit image failed", error);
      // Pass the specific refusal message if available
      if (error.message.startsWith('AI Menolak')) {
         throw error;
      }
      throw error;
  }
};

export const startVideoGeneration = async (
  ai: GoogleGenAI,
  prompt: string,
  resolution: Resolution,
  aspectRatio: VideoAspectRatio,
  startImage?: { data: string; mimeType: string; }
) => {
  const operation = await ai.models.generateVideos({
    model: VIDEO_MODEL,
    prompt,
    ...(startImage && {
        image: {
            imageBytes: startImage.data,
            mimeType: startImage.mimeType,
        }
    }),
    config: {
      numberOfVideos: 1,
      resolution: resolution,
      aspectRatio: aspectRatio,
    }
  });
  return operation;
};

export const getVideoOperationStatus = async (ai: GoogleGenAI, operation: any) => {
    return await ai.operations.getVideosOperation({ operation: operation });
};

// Chat Functionality
export const createChatSession = () => {
    const apiKey = getApiKey();
    if (!apiKey) throw new Error("API Key not found");

    const ai = new GoogleGenAI({ apiKey });
    return ai.chats.create({
        model: CHAT_MODEL,
        config: {
            systemInstruction: MELDA_SYSTEM_INSTRUCTION,
        },
    });
};

export const sendMessage = async (chat: Chat, message: string): Promise<string> => {
    try {
        const result: GenerateContentResponse = await chat.sendMessage({ message });
        return result.text || "Maaf, saya tidak dapat menghasilkan respons saat ini.";
    } catch (error: any) {
        console.error("Chat error:", error);

        // Improve error message for 403 Permission Denied
        if (error.message && error.message.includes("403")) {
           throw new Error("Akses Ditolak (403): Kunci API Anda tidak memiliki izin untuk model ini. Pastikan API Key valid dan billing aktif.");
        }

        throw error;
    }
};

